#include<algorithm>

using namespace std;

typedef long long ll;





const ll mod = 1e9;



vector<ll> q,p;



bool ok(ll x,ll n,ll k)

{

    ll ans = 0;

    sort(q.begin(),q.end(),greater<ll>());

    sort(p.begin(),p.end());

    int s1 = q.size(),s2 = p.size();

    for(int i = 0; i < s1; ++i)

    {

        int l = i,r = s1-1;

        while(l < r)

        {

            int mid = l + r +1 >>1;

            if(q[i]*q[mid] <= x) l = mid;

            else r = mid - 1;

        }

        if(l > i) ans += l -i ;

    }

    for(int i = 0; i < s2; ++i)

    {

        int l = i,r = s2 - 1;

        while(l < r)

        {

            int mid = l + r + 1 >> 1;

            if(p[i]*p[mid] <= x) l = mid;

            else r = mid - 1;

        }

        if(l > i) ans += l - i ;

    }

    if(ans >= k) return 1;

    reverse(q.begin(),q.end());

    reverse(p.begin(),p.end());

    for(int i = 0; i < s1; ++i)

    {

        int l = -1,r = s2-1;

        while(l < r)

        {

            int mid = l + r + 1>>1;

            if(q[i] * p[mid] <=  x) l = mid;

            else r = mid - 1;

        }

        if(l != -1) ans += l + 1;

    }

    return ans >= k;





}

int main()

{

    ll n,k,a;

    scanf("%lld%lld",&n,&k);



    for(int i = 1; i <= n; ++i)

    {

        scanf("%lld",&a);

        if(a<0) q.push_back(a);

        else  p.push_back(a);

    }

    ll l = - mod * mod ,r = mod *mod;

    while(l < r)

    {

        ll mid = l + r >>1;

        if(ok(mid,n,k)) r = mid;

        else l = mid + 1;

    }

    cout << r;

}

