  while(c>47&&c<58){x=x*10+c-48,c=CH();}return f?-x:x;

}

static inline void OUT(long x){if(x<0)putchar('-'),x=-x;if(x>=10)OUT(x/10);putchar(x%10+48);}

static void radix(int bitsOffset,UL N,UL *source,UL *dest)

{

  //https://cubic.org/docs/download/radix_ar.c

  UL count[256],*cp,*sp,s,c,i;

  cp=count;

  for(i=256;i>0;--i,++cp)*cp=0;

  sp=source;

